export const getWordData = (word) =>
  [...Y34_WORD_DATA, ...Y56_WORD_DATA].find(e => e.word === word.toLowerCase()) ?? null;
export const getDefinition = (word) => {
  const entry = getWordData(word);
  return entry ? entry.definitions.ages7to10 : null;
};
export const getSessionWords = ({ yearBand = 'y34', difficulty = 'all', includeEarlier = true }) => {
  const pool = yearBand === 'y56' && includeEarlier ? [...Y34_WORD_DATA, ...Y56_WORD_DATA] : yearBand === 'y56' ? Y56_WORD_DATA : Y34_WORD_DATA;
  return pool.filter(e => difficulty === 'all' || e.difficulty === difficulty);
};
export const getWordsByPattern = (r) => [...Y34_WORD_DATA, ...Y56_WORD_DATA].filter(e => e.spellingRule === r);
export const getWordsByPatternGroup = (g) => [...Y34_WORD_DATA, ...Y56_WORD_DATA].filter(e => e.patternGroup === g);
export const getCorePatternWords = () => [...Y34_WORD_DATA, ...Y56_WORD_DATA].filter(e => e.corePatternWord);

export default {
  y34: { label:'Year 3/4', ageRange:[7,9], words:Y34_WORD_DATA, statutory:Y34_STATUTORY },
  y56: { label:'Year 5/6', ageRange:[9,11], words:Y56_WORD_DATA, statutory:Y56_STATUTORY },
  ks2: { label:'KS2', ageRange:[7,11], words:[...Y34_WORD_DATA,...Y56_WORD_DATA], statutory:KS2_ALL_STATUTORY },
  getWordData, getDefinition, getSessionWords, getWordsByPattern, getWordsByPatternGroup, getCorePatternWords,
};
